@spec tm_fx_region_spec  src=tests/specs/tm_fx_region_spec.lua  loc=1694  sha=37ed80d  cases=61
@exercises dataStore (h.ds), midiManager (h.fm), trackerManager (h.tm), trackerView (h.vm)
@surface   ds:get, fm:dump, ds:assign, tm:rebuild, tm:getChannel, tm:addEvent, tm:flush, tm:assignParked, tm:deleteParked, tm:addParked, tm:subscribe, vm:addFxStage, vm:noteFx, vm:removeFxStage
@harness   mk

# Intent
  Note macros v2: region hosts. The N=0 vibrato pb seat stream proves the generator-side substrate
  (ds, 4.6 producer split, reconcile, G4 round-trip). see design/note-macros-v2.md

# Helpers
  @fn centsToRaw(cents, pbRange)  @ 11-13
  @fn inPbWindow(h, chan, ppq)  @ 17-22
      -- A seat is recognized purely by region membership: any pb inside a live region's span (bounds
      -- inclusive of endppq, so the terminal re-centre seat counts). see design/note-macros-v2.md § Route-by-window
  @fn authoredPb(h, chan, ppq)  @ 26-30
      -- An authored pb on the wire: one no live pb window covers (a covered pb is a seat). `val` is raw
      -- (centsToRaw of wire-cents + detune); `cents` the persisted intent. nil while a window parks it off.
  @fn derivedPbs(h, chan)  @ 34-40
      -- The seated curve of a pb-replace region, hidden from columns. Seats are markerless -- there is no
      -- marker to filter on; the live window IS their identity. Recognized purely by region membership.
  @fn derivedPb(h, chan, ppq)  @ 42-44
  @fn stashOfType(h, evType)  @ 47-53
      -- The cc / pb slice of the unified fxParked off-take stash.
  @fn inCcSpan(h, chan, ppq)  @ 57-62
      -- Half-open region membership on a channel (matches production's covered()): a cc-replace seat lives
      -- in [startppq, endppq). see design/note-macros-v2.md § Route-by-window
  @fn fillRecords(h, chan, cc)  @ 66-74
      -- The seated replace curve on a cc target, hidden from columns. Seats are markerless -- the live region
      -- span IS their identity; the authored cc it covers is parked off-take.
  @fn fillsOf(h, chan, cc)  @ 75-82
  @fn ccFillAt(h, chan, cc, ppq)  @ 83-85
  @fn authoredCC(h, chan, cc, ppq)  @ 89-94
      -- A non-derived authored cc on the take, outside any live cc-replace window (an in-window cc is a
      -- markerless seat, not authored); nil once a window parks the authored cc off.
  @fn injectRegion(h, over)  @ 97-102
      -- A region is channel x ppq span + fx; no host note. Inject via ds, then rebuild.
  @fn anyNoteOnChan(h, chan)  @ 104-109
  @fn addNote(h, over)  @ 115-120
  @fn injectArp(h, over)  @ 122-127
  @fn derivedNotes(h)  @ 131-143
      -- Derived notes the region produced -- routed out of columns, tagged with the region
      -- uuid. Sorted by onset then lane; identity swing, so ppq == the logical step time.
  @fn field(ns, k)  @ 145
  @fn authoredPitches(h)  @ 149-156
      -- Authored (non-derived) note pitches still sounding in the take, sorted. Empty when a
      -- replace region has parked the whole chord off-take.

# Cases
  @case 'fx region (N=0): vibrato over a span seats a free-LFO pb stream with no host note'  [harness]  @ 163-173
  @case 'fx region: pb seats re-centre the channel at the region window end'  [harness]  @ 179-188
  @case 'G4: region pb seat stream is byte-identical across rebuild -> flush'  [harness]  @ 194-208
  @case 'G2: removing the region leaves no pb seat after reconcile'  [harness]  @ 214-228
  @case 'replace: arp over a held triad packs into lane 1; the chord parks off the take'  [harness]  @ 234-246
  @case 'replace: a PA under the parked host parks off-take with it, restores on unpark'  [harness]  @ 252-286
  @case 'two rebuilds over an arp region allocate byte-identical derived notes + lanes'  [harness]  @ 292-304
  @case 'replace: arp samples the playing notes continuously, with no collision nudge'  [harness]  @ 308-319
  @case 'replace: a parked member tail is realised against its same-lane successor'  [harness]  @ 323-331
  @case 'chain [arp, velPattern]: the pattern accents the arp steps'  [harness]  @ 337-348
  @case 'chain [velPattern, arp]: the chord takes the pattern first, the arp reads the folded stream'  [harness]  @ 352-364
  @case 'velPattern alone owns the note stream: the chord parks and re-emits re-velocitied'  [harness]  @ 368-378
  @case 'replace: a parked member tail is clipped by an on-take note after the region'  [harness]  @ 382-395
  @case 'replace: a parked member tail is clipped by a parked note in a later region'  [harness]  @ 399-416
  @case 'replace husk (no kinds) parks nothing -- its members keep sounding'  [harness]  @ 420-426
  @case 'replace: removing the region restores the parked chord to the take'  [harness]  @ 430-445
  @case 'G4: replace arp + parked chord are byte-identical across rebuild -> flush'  [harness]  @ 449-461
  @case 'park identity (note): render cell carries chan+uuid; the fxParked stash is logical-only'  [harness]  @ 467-480
  @case 'park round-trip carries arbitrary authored metadata, not just whitelisted fields'  [harness]  @ 484-496
  @case 'park identity (cc): render cell carries chan+ppq; the fxParkedCC stash is logical-only'  [harness]  @ 500-520
  @case 'assignParked (note): edit a parked pitch -> stash updated, still parked, renders the new pitch'  [harness]  @ 526-537
  @case 'deleteParked (note): a parked note leaves the stash and is not restored while still covered'  [harness]  @ 541-550
  @case 'addParked (note): typing into a replace window stashes a logical spec (minted uuid), off the take'  [harness]  @ 554-574
  @case 'parked cc: assignParked then deleteParked edits the off-take cc stash symmetrically'  [harness]  @ 578-600
  @case 'shrinking a cc-replace window restores the authored cc value, not the fill it sat under'  [harness]  @ 606-646
  @case 'one flush, one rebuild: a parked edit + a normal note land together (the multi-select guard)'  [harness]  @ 650-664
  @case 'parked-only flush drives exactly one rebuild (no mm round-trip)'  [harness]  @ 668-678
  @case 'fxParked dataChanged (undo rewind) rebuilds the grid'  [harness]  @ 682-691
  @case 'augment by kind: a continuous (vibrato) region leaves its covered notes sounding'  [harness]  @ 697-704
  @case 'arp over a span with no sounding notes emits nothing'  [harness]  @ 710-715
  @case 'fx region: the producer hands the generator notes/pas/ccs/ats input streams'  [harness]  @ 721-751
  @case 'fx region: an OPEN member clips to the next same-lane onset, not the window end'  [harness]  @ 755-778
  @case 'fx region: host.pb carries authored pb breakpoints, excluding absorber fakes'  [harness]  @ 782-806
  @case 'fx region: pb replace seats the absolute curve on the base lane, no carrier'  [harness]  @ 812-845
  @case 'fx region: pb replace with no authored base seats the curve verbatim'  [harness]  @ 849-868
  @case 'fx chain (continuous): [replace, augment] -- the augment stage wobbles the replaced curve'  [harness]  @ 874-902
  @case 'fx chain (continuous): [augment, replace] -- the replace stage overwrites the folded stream'  [harness]  @ 906-932
  @case 'fx region (pb): two overlapping replace regions -- later storage wins pointwise, not summed'  [harness]  @ 938-964
  @case 'fx region (pb): a later replace region wipes an earlier augment (storage = precedence)'  [harness]  @ 968-996
  @case 'fx region (pb): overlapping replace regions with differing windows -- each owns its exclusive tail'  [harness]  @ 1000-1030
  @case 'fx region (cc): two overlapping replace regions -- later storage wins, not the additive fold'  [harness]  @ 1034-1060
  @case 'fx region (cc augment): overlapping differing windows -- each augment folds only in its own window'  [harness]  @ 1064-1095
  @case 'fx region (pb): differing-window overlap seats are byte-stable across a no-change rebuild'  [harness]  @ 1099-1144
  @case 'fx region: pb replace rides the curve over the detune -- I1 holds'  [harness]  @ 1148-1173
  @case 'fx region: removing a pb replace region restores the authored wire'  [harness]  @ 1177-1202
  @case 'fx region: pb replace densifies a curved segment split by a detune onset'  [harness]  @ 1206-1239
  @case 'fx region: a dense pb replace curve seats markerless -- no uuid, no metadata sidecar'  [harness]  @ 1245-1272
  @case 'fx region: removing a pb replace region sweeps its seats, leaving only the restored authored pb'  [harness]  @ 1276-1308
  @case 'fx region (cc replace): the generated curve lands on the target cc lane; no carrier'  [harness]  @ 1314-1340
  @case 'fx region (cc replace): removing the region restores the parked cc and drops the fill'  [harness]  @ 1344-1370
  @case 'G4 (cc replace): the fill is byte-identical and re-adds nothing across a no-change rebuild'  [harness]  @ 1374-1400
  @case 'cc replace: a dense fill curve seats markerlessly (no uuid, no eventMeta)'  [harness]  @ 1404-1424
  @case 'fx region (cc augment): un-automated target seats base(rest) + macro, markerless, off columns'  [harness]  @ 1430-1452
  @case 'fx region (cc augment): over authored automation the seat is authored-base + macro'  [harness]  @ 1456-1476
  @case 'fx region (cc augment): two overlapping regions sum every stream (N-stream regression guard)'  [harness]  @ 1480-1508
  @case 'fx region (cc augment): region.fx.rest overrides the default resting base'  [harness]  @ 1512-1530
  @case 'note-host augment (cc): a sounding note drives summed seats like a degenerate region'  [harness]  @ 1534-1563
  @case 'replace: a preceding on-take tail clips at the parked chord onset, not past it'  [harness]  @ 1569-1585
  @case 'replace: a derived tile is not truncated by a parked member it replaced'  [harness]  @ 1589-1605
  @case 'deleting a self-parked [trill, vibrato] host leaves no orphaned pb seats'  [harness]  @ 1611-1636
  @case 'removing the note kind from a self-parked [autopan, trill] host keeps its authored cc parked'  [harness]  @ 1642-1691

